long long solve(std::vector<long long> nums, long long maxC) {
    // Create a copy of the array to modify
    std::vector<long long> arr = nums;
    int n = arr.size();

    // Helper function to compute GCD of two numbers
    auto gcd = [](long long a, long long b) {
        while (b) {
            long long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    };

    // Helper function to compute GCD of a vector
    auto gcdVector = [](const std::vector<long long>& vec) {
        long long g = vec[0];
        for (size_t i = 1; i < vec.size(); ++i) {
            g = gcd(g, vec[i]);
            if (g == 1) break;
        }
        return g;
    };

    // Helper function to check if a subarray is stable
    auto isStable = [](const std::vector<long long>& sub) {
        long long g = sub[0];
        for (size_t i = 1; i < sub.size(); ++i) {
            g = gcd(g, sub[i]);
            if (g == 1) break;
        }
        return g >= 2;
    };

    // Helper function to find the maximum stable subarray length in a window
    auto maxStableInWindow = [](const std::vector<long long>& arr, int left, int right) {
        int maxLen = 0;
        for (int i = left; i <= right; ++i) {
            int len = 1;
            long long g = arr[i];
            for (int j = i + 1; j <= right; ++j) {
                g = gcd(g, arr[j]);
                if (g >= 2) {
                    len++;
                } else {
                    break;
                }
            }
            maxLen = std::max(maxLen, len);
        }
        return maxLen;
    };

    // Try to modify elements to minimize the maximum stable subarray length
    // We can use a sliding window approach to find the optimal modification
    int left = 0;
    int right = 0;
    int maxStable = 0;
    int count = 0;

    while (right < n) {
        // Check if the current window can be made stable
        // If not, we need to modify elements
        long long currentGcd = arr[right];
        for (int i = right; i >= left; --i) {
            currentGcd = gcd(currentGcd, arr[i]);
            if (currentGcd >= 2) {
                break;
            }
        }

        if (currentGcd >= 2) {
            // The current window is stable
            maxStable = std::max(maxStable, right - left + 1);
            right++;
        } else {
            // We need to modify elements to make the window stable
            // Try to find the best element to modify
            int bestPos = -1;
            int bestGcd = 0;
            for (int i = left; i <= right; ++i) {
                long long tempGcd = arr[i];
                for (int j = i; j <= right; ++j) {
                    tempGcd = gcd(tempGcd, arr[j]);
                    if (tempGcd >= 2) {
                        break;
                    }
                }
                if (tempGcd >= 2) {
                    bestPos = i;
                    bestGcd = tempGcd;
                    break;
                }
            }

            if (bestPos != -1) {
                // Modify the best position to make the window stable
                arr[bestPos] = bestGcd;
                count++;
                if (count > maxC) {
                    break;
                }
                right++;
            } else {
                // No way to make the window stable, so we need to move left
                left++;
            }
        }
    }

    return maxStable;
