		for i := 1; i < len(vec); i++ {
			g = gcd(g, vec[i])
			if g == 1 {
				break
			}
		}
		return g
	}

	// Helper function to check if a subarray is stable
	isStable := func(sub []int64) bool {
		g := sub[0]
		for i := 1; i < len(sub); i++ {
			g = gcd(g, sub[i])
			if g == 1 {
				return false
			}
		}
		return true
	}

